SELECT COUNT(DISTINCT p.id) FROM posts p INNER JOIN categories c ON c.id = p.category_id LEFT JOIN post_tags pt ON pt.post_id = p.id LEFT JOIN tags t ON t.id = pt.tag_id WHERE p.status = 'PUBLISHED'
AND ( LOWER(p.title) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(p.summary) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
AND c.slug = #{categorySlug}
AND t.slug = #{tagSlug}

SELECT DISTINCT
FROM posts p INNER JOIN categories c ON c.id = p.category_id LEFT JOIN post_tags pt ON pt.post_id = p.id LEFT JOIN tags t ON t.id = pt.tag_id WHERE p.status = 'PUBLISHED'
AND ( LOWER(p.title) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(p.summary) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
AND c.slug = #{categorySlug}
AND t.slug = #{tagSlug}
ORDER BY p.published_at DESC LIMIT #{offset}, #{limit}

SELECT

FROM posts p
INNER JOIN categories c ON c.id = p.category_id
WHERE p.status = #{status}
ORDER BY p.published_at DESC
LIMIT #{limit}

SELECT COUNT(DISTINCT p.id) FROM posts p INNER JOIN categories c ON c.id = p.category_id WHERE 1 = 1
AND ( LOWER(p.title) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(p.summary) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(p.slug) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
AND p.status = #{status}
AND p.category_id = #{categoryId}

SELECT

FROM posts p
INNER JOIN categories c ON c.id = p.category_id
WHERE 1 = 1

    AND (
        LOWER(p.title) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(p.summary) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(p.slug) LIKE CONCAT('%', LOWER(#{keyword}), '%')
    )


    AND p.status = #{status}


    AND p.category_id = #{categoryId}

ORDER BY p.updated_at DESC
LIMIT #{offset}, #{limit}
